<?php
namespace App\Services\Feature;use App\Models\Workspace;
class FeatureService{public function enabled(string $featureKey,?Workspace $workspace=null):bool{$config=config("workproof.features.$featureKey");if($config!==null)return (bool)$config;$flag=$workspace?->settings?->feature_flags[$featureKey]??null;if($flag!==null)return (bool)$flag;$feature=$workspace?->subscription?->plan?->features()->where('feature_key',$featureKey)->first();return $feature?(bool)$feature->enabled:false;}public function limit(string $limitKey,?Workspace $workspace=null):mixed{$flag=$workspace?->settings?->feature_flags[$limitKey]??null;if($flag!==null)return $flag;$plan=$workspace?->subscription?->plan;if($plan && isset($plan->{$limitKey}))return $plan->{$limitKey};$feature=$plan?->features()->where('feature_key',$limitKey)->first();return $feature?->value;}}
